// Compute today's summary from Google Sheets data
const today = new Date().toISOString().split('T')[0];
const items = $input.all();

let total = 0, hot = 0, warm = 0, cold = 0, enrolled = 0;
const sources = {};

for (const item of items) {
  const ts = String(item.json.Timestamp || '');
  if (!ts.startsWith(today)) continue;
  total++;
  const score = String(item.json['Lead Score'] || '').trim();
  if (score === 'Hot') hot++;
  else if (score === 'Warm') warm++;
  else cold++;
  if (String(item.json['Lead Status']).toLowerCase() === 'enrolled') enrolled++;
  const src = String(item.json['Source Channel'] || 'Other');
  sources[src] = (sources[src] || 0) + 1;
}

const srcSummary = Object.entries(sources).map(([k,v]) => `${k}: ${v}`).join(', ');

return [{
  json: { total, hot, warm, cold, enrolled, sources_summary: srcSummary, date: today }
}];

